}
const memberSql = sqlLiteral(member);
const sql = `
WITH member_rows AS (
  SELECT
    rm."Membership" AS membership,
    rm."Status" AS status,
    rm."Payment" AS payment,
    rm."Venue ID" AS venue_id,
    rm."British Tennis Number" AS british_tennis_number,
    rm."Email address" AS email_address,
    rm."Phone number" AS phone_number,
    rm."Mobile number" AS mobile_number,
    rm."Address 1" AS address_1,
    rm."Address 2" AS address_2,
    rm."Address 3" AS address_3,
    rm."Town" AS town,
    rm."County" AS county,
    rm."Postcode" AS postcode,
    rm."Start Date" AS start_date,
    rm."Date joined venue" AS date_joined_venue,
    rm."Cost" AS cost,
    rm."Paid" AS paid_total,
    rm."Paid Cash" AS paid_cash,
    rm."Paid Credit Card" AS paid_credit_card,
    rm."Paid Direct Debit" AS paid_direct_debit
  FROM public.raw_members rm
  WHERE coalesce(rm.is_current, true) = true
    AND concat(rm."First name", ' ', rm."Last name") = ${memberSql}
  ORDER BY rm."Membership"
),
contact_rows AS (
  SELECT
    rc."Venue ID" AS venue_id,
    rc."Email address" AS email_address,
    rc."Phone number" AS phone_number,
    rc."Mobile number" AS mobile_number,
    rc."Address 1" AS address_1,
    rc."Address 2" AS address_2,
    rc."Address 3" AS address_3,
    rc.town,
    rc.county,
    rc.postcode
  FROM public.raw_contacts rc
  WHERE coalesce(rc.is_current, true) = true
    AND concat(rc."First name", ' ', rc."Last name") = ${memberSql}
)
SELECT
  ${memberSql}::text AS member,
  COALESCE((SELECT json_agg(to_jsonb(mr)) FROM member_rows mr), '[]'::json) AS member_rows,
  COALESCE((SELECT json_agg(to_jsonb(cr)) FROM contact_rows cr), '[]'::json) AS contact_rows,
  COALESCE(
    (
      SELECT to_jsonb(cr)
      FROM contact_rows cr
      ORDER BY
        CASE WHEN NULLIF(trim(cr.address_1), '') IS NOT NULL THEN 0 ELSE 1 END,
        CASE WHEN NULLIF(trim(cr.postcode), '') IS NOT NULL THEN 0 ELSE 1 END,
        CASE WHEN NULLIF(trim(cr.email_address), '') IS NOT NULL THEN 0 ELSE 1 END,
        CASE WHEN NULLIF(trim(cr.mobile_number), '') IS NOT NULL THEN 0 ELSE 1 END,
        CASE WHEN NULLIF(trim(cr.phone_number), '') IS NOT NULL THEN 0 ELSE 1 END
      LIMIT 1
    ),
    '{}'::jsonb
  ) AS best_contact;
`;
return [{ json: { member, n8n_base_url: n8nBaseUrl, sql } }];

